INSERT INTO kends.sypo_version (ID, HMEROMHNIA, VERSION, PERIGRAFH) VALUES (6, '2021-01-13', '1.14', 'Προσθήκη δυνατότητας εκτύπωσης Ταυτοτήτων,αν δεν  έχει παρουσιαστεί ένας  Ν/Σ δεν βγαίνει κανένα εκτυπωτικό,προσθήκη table με τις μονάδες ανά επαρχία/τοπωνύμιο/Νομό/Γεωγραφικό Διαμέρισμα.Διόρθωση bug όταν παίρνει αναβολή ενας Ν/Σ.')